// nodes/conditionNode.js — Conditional branching node
import { BaseNode } from '../components/BaseNode';

const config = {
  title: 'Condition',
  icon: '🔀',
  color: 'var(--pf-pink)',
  fields: [
    { key: 'operator', label: 'Operator', type: 'select', defaultValue: 'contains',
      options: ['contains', 'equals', 'greater than', 'less than', 'starts with', 'ends with'] },
    { key: 'value', label: 'Compare value', type: 'text', placeholder: 'value to compare' },
  ],
  inputs:  [{ id: 'input', label: 'Input' }],
  outputs: [{ id: 'true',  label: 'True'  }, { id: 'false', label: 'False' }],
};

export const ConditionNode = (props) => <BaseNode {...props} config={config} />;
